70	// --- exec mock state ---
71	
72	type ExecCallback = (
73	  error: Error | null,
74	  stdout: string,
75	  stderr: string,
76	) => void;
77	
78	let execCallback: ExecCallback;
79	let lastExecCommand: string | undefined;
80	let stdinWrittenData: string;
81	let stdinErrorHandler: ((err: Error) => void) | undefined;
82	let mockKill: ReturnType<typeof vi.fn>;
83	
84	function setStatusLineConfig(
85	  config: { type: string; command: string } | undefined,
86	) {
87	  mockSettings.merged = config ? { ui: { statusLine: config } } : {};
88	}
89	
90	describe('useStatusLine', () => {
91	  // Must import dynamically after mocks are set up
92	  let useStatusLine: typeof import('./useStatusLine.js').useStatusLine;
93	
94	  beforeEach(async () => {
95	    vi.useFakeTimers();
96	    vi.clearAllMocks();
97	    lastExecCommand = undefined;
98	    stdinWrittenData = '';
99	    stdinErrorHandler = undefined;
100	    mockKill = vi.fn();
101	
102	    // Set up exec mock implementation
103	    vi.mocked(child_process.exec).mockImplementation(((
104	      cmd: string,
105	      _opts: unknown,
106	      cb: ExecCallback,
107	    ) => {
108	      lastExecCommand = cmd;
109	      execCallback = cb;
110	      stdinWrittenData = '';
111	      stdinErrorHandler = undefined;
112	      return {
113	        stdin: {
114	          on: vi.fn((_event: string, handler: (err: Error) => void) => {
115	            stdinErrorHandler = handler;
116	          }),
117	          write: vi.fn((data: string) => {
118	            stdinWrittenData += data;
119	            return true;
120	          }),
121	          end: vi.fn(),
122	        },
123	        kill: mockKill,
124	        killed: false,
125	      };
126	    }) as unknown as typeof child_process.exec);
127	
128	    // Reset mutable mock state
129	    setStatusLineConfig(undefined);
130	    mockUIState.sessionStats.lastPromptTokenCount = 100;
131	    mockUIState.currentModel = 'test-model';
132	    mockUIState.branchName = 'main';
133	    mockUIState.sessionStats.metrics.tools.totalCalls = 0;
134	    mockUIState.sessionStats.metrics.files.totalLinesAdded = 0;
135	    mockUIState.sessionStats.metrics.files.totalLinesRemoved = 0;
136	    mockVimMode.vimEnabled = false;
137	    mockVimMode.vimMode = 'INSERT';
138	
139	    // Dynamic import to get fresh module after mocks
140	    const mod = await import('./useStatusLine.js');
141	    useStatusLine = mod.useStatusLine;
142	  });
143	
144	  afterEach(() => {
145	    vi.useRealTimers();
146	  });
147	
148	  // --- getStatusLineConfig validation (tested through the hook) ---
149	
150	  describe('config validation', () => {
151	    it('returns null when no statusLine config is set', () => {
152	      const { result } = renderHook(() => useStatusLine());
153	      expect(result.current.text).toBeNull();
154	      expect(child_process.exec).not.toHaveBeenCalled();
155	    });
156	
157	    it('returns null when statusLine type is not "command"', () => {
158	      setStatusLineConfig({ type: 'invalid', command: 'echo hi' });
159	      const { result } = renderHook(() => useStatusLine());
160	      expect(result.current.text).toBeNull();
161	      expect(child_process.exec).not.toHaveBeenCalled();
162	    });
163	
164	    it('returns null when command is empty string', () => {
165	      setStatusLineConfig({ type: 'command', command: '' });
166	      const { result } = renderHook(() => useStatusLine());
167	      expect(result.current.text).toBeNull();
168	      expect(child_process.exec).not.toHaveBeenCalled();
169	    });
170	
171	    it('returns null when command is whitespace only', () => {
172	      setStatusLineConfig({ type: 'command', command: '   ' });
173	      const { result } = renderHook(() => useStatusLine());
174	      expect(result.current.text).toBeNull();
175	      expect(child_process.exec).not.toHaveBeenCalled();
176	    });
177	  });
178	
179	  // --- Command execution ---
180	
181	  describe('command execution', () => {
182	    it('executes configured command on mount', () => {
183	      setStatusLineConfig({ type: 'command', command: 'echo hello' });
184	      renderHook(() => useStatusLine());
185	      expect(child_process.exec).toHaveBeenCalledOnce();
186	      expect(lastExecCommand).toBe('echo hello');
187	    });
188	
189	    it('passes correct options to exec', () => {
190	      setStatusLineConfig({ type: 'command', command: 'echo hello' });
191	      renderHook(() => useStatusLine());
192	      const callArgs = vi.mocked(child_process.exec).mock.calls[0];
193	      const opts = callArgs[1] as {
194	        cwd: string;
195	        timeout: number;
196	        maxBuffer: number;
197	      };
198	      expect(opts.cwd).toBe('/test/dir');
199	      expect(opts.timeout).toBe(5000);
200	      expect(opts.maxBuffer).toBe(1024 * 10);
201	    });
202	
203	    it('returns first line of stdout as text', async () => {
204	      setStatusLineConfig({ type: 'command', command: 'echo hello' });
205	      const { result } = renderHook(() => useStatusLine());
206	
207	      await act(async () => {
208	        execCallback(null, 'hello world\n', '');
209	      });
210	
211	      expect(result.current.text).toBe('hello world');
212	    });
213	
214	    it('returns only the first line when stdout has multiple lines', async () => {
215	      setStatusLineConfig({ type: 'command', command: 'echo lines' });
216	      const { result } = renderHook(() => useStatusLine());
217	
218	      await act(async () => {
219	        execCallback(null, 'first line\nsecond line\n', '');
220	      });
221	
222	      expect(result.current.text).toBe('first line');
223	    });
224	
225	    it('returns null when command fails', async () => {
226	      setStatusLineConfig({ type: 'command', command: 'bad-cmd' });
227	      const { result } = renderHook(() => useStatusLine());
228	
229	      await act(async () => {
230	        execCallback(new Error('command not found'), '', '');
231	      });
232	
233	      expect(result.current.text).toBeNull();
234	    });
235	
236	    it('returns null when stdout is empty', async () => {
237	      setStatusLineConfig({ type: 'command', command: 'echo -n' });
238	      const { result } = renderHook(() => useStatusLine());
239	
240	      await act(async () => {
241	        execCallback(null, '', '');
242	      });
243	
244	      expect(result.current.text).toBeNull();
245	    });
246	  });
247	
248	  // --- stdin JSON input ---
249	
250	  describe('stdin JSON input', () => {
251	    it('writes JSON to stdin with session context', () => {
252	      setStatusLineConfig({ type: 'command', command: 'cat' });
253	      renderHook(() => useStatusLine());
254	
255	      const input = JSON.parse(stdinWrittenData);
256	      expect(input.session_id).toBe('test-session');
