298	
299	    it('includes context window usage data', () => {
300	      mockUIState.sessionStats.lastPromptTokenCount = 65536;
301	      setStatusLineConfig({ type: 'command', command: 'cat' });
302	      renderHook(() => useStatusLine());
303	
304	      const input = JSON.parse(stdinWrittenData);
305	      expect(input.context_window.context_window_size).toBe(131072);
306	      expect(input.context_window.used_percentage).toBe(50);
307	      expect(input.context_window.remaining_percentage).toBe(50);
308	      expect(input.context_window.current_usage).toBe(65536);
309	    });
310	  });
311	
312	  // --- Stale generation handling ---
313	
314	  describe('stale generation', () => {
315	    it('ignores callback from stale generation and accepts fresh one', async () => {
316	      setStatusLineConfig({ type: 'command', command: 'echo test' });
317	      const { result, rerender } = renderHook(() => useStatusLine());
318	
319	      // Capture first callback
320	      const firstCallback = execCallback;
321	
322	      // Trigger a state change to cause re-execution
323	      mockUIState.currentModel = 'new-model';
324	      rerender();
325	
326	      // Advance debounce timer — triggers second exec
327	      await act(async () => {
328	        vi.advanceTimersByTime(300);
329	      });
330	
331	      // Capture second (current) callback
332	      const secondCallback = execCallback;
333	
334	      // Resolve the stale first callback — should be ignored
335	      await act(async () => {
336	        firstCallback(null, 'stale output\n', '');
337	      });
338	      expect(result.current.text).toBeNull();
339	
340	      // Resolve the fresh second callback — should be accepted
341	      await act(async () => {
342	        secondCallback(null, 'fresh output\n', '');
343	      });
344	      expect(result.current.text).toBe('fresh output');
345	    });
346	  });
