349	
350	  describe('debouncing', () => {
351	    it('debounces rapid state changes to a single exec', async () => {
352	      setStatusLineConfig({ type: 'command', command: 'echo test' });
353	      const { rerender } = renderHook(() => useStatusLine());
354	
355	      // Initial mount exec
356	      expect(child_process.exec).toHaveBeenCalledTimes(1);
357	
358	      // Rapid state changes
359	      mockUIState.currentModel = 'model-1';
360	      rerender();
361	      mockUIState.currentModel = 'model-2';
362	      rerender();
363	      mockUIState.currentModel = 'model-3';
364	      rerender();
365	
366	      // Before debounce expires, no additional execs
367	      expect(child_process.exec).toHaveBeenCalledTimes(1);
368	
369	      // After debounce
370	      await act(async () => {
371	        vi.advanceTimersByTime(300);
372	      });
373	
374	      // Should have exactly one debounced exec (total 2: mount + debounced)
375	      expect(child_process.exec).toHaveBeenCalledTimes(2);
376	    });
377	  });
378	
379	  // --- Config removal clears output ---
380	
381	  describe('config removal', () => {
382	    it('clears output when config is removed', async () => {
383	      setStatusLineConfig({ type: 'command', command: 'echo hello' });
384	      const { result, rerender } = renderHook(() => useStatusLine());
385	
386	      await act(async () => {
387	        execCallback(null, 'hello\n', '');
388	      });
389	      expect(result.current.text).toBe('hello');
