402	    it('kills active child process on unmount', () => {
403	      setStatusLineConfig({ type: 'command', command: 'sleep 10' });
404	      const { unmount } = renderHook(() => useStatusLine());
405	
406	      expect(mockKill).not.toHaveBeenCalled();
407	      unmount();
408	      expect(mockKill).toHaveBeenCalled();
409	    });
