7	import { useState, useEffect, useRef, useCallback } from 'react';
8	import { exec, type ChildProcess } from 'child_process';
9	import { createDebugLogger } from '@qwen-code/qwen-code-core';
10	import { useSettings } from '../contexts/SettingsContext.js';
11	import { useUIState } from '../contexts/UIStateContext.js';
12	import { useConfig } from '../contexts/ConfigContext.js';
13	import { useVimMode } from '../contexts/VimModeContext.js';
14	import type { SessionMetrics } from '../contexts/SessionContext.js';
15	
16	/**
17	 * Structured JSON input passed to the status line command via stdin.
18	 * This allows status line commands to display context-aware information
19	 * (model, token usage, session, etc.) without running extra queries.
20	 */
21	export interface StatusLineCommandInput {
22	  session_id: string;
23	  version: string;
24	  model: {
25	    display_name: string;
26	  };
27	  context_window: {
28	    context_window_size: number;
29	    used_percentage: number;
30	    remaining_percentage: number;
31	    current_usage: number;
32	    total_input_tokens: number;
33	    total_output_tokens: number;
34	  };
35	  workspace: {
36	    current_dir: string;
37	  };
38	  git?: {
39	    branch: string;
40	  };
41	  metrics: {
42	    models: Record<
43	      string,
44	      {
45	        api: {
46	          total_requests: number;
47	          total_errors: number;
48	          total_latency_ms: number;
49	        };
50	        tokens: {
51	          prompt: number;
52	          completion: number;
53	          total: number;
54	          cached: number;
55	          thoughts: number;
56	        };
57	      }
58	    >;
59	    files: {
60	      total_lines_added: number;
61	      total_lines_removed: number;
62	    };
63	  };
64	  vim?: {
65	    mode: string;
66	  };
67	}
68	
69	interface StatusLineConfig {
70	  type: 'command';
71	  command: string;
72	}
73	
74	const debugLog = createDebugLogger('STATUS_LINE');
75	
76	function getStatusLineConfig(
77	  settings: ReturnType<typeof useSettings>,
78	): StatusLineConfig | undefined {
79	  const raw = settings.merged.ui?.statusLine;
80	  if (
81	    raw &&
82	    typeof raw === 'object' &&
83	    'type' in raw &&
84	    raw.type === 'command' &&
85	    'command' in raw &&
86	    typeof raw.command === 'string' &&
87	    raw.command.trim().length > 0
88	  ) {
89	    const config: StatusLineConfig = {
90	      type: 'command',
91	      command: raw.command,
92	    };
93	    return config;
94	  }
95	  return undefined;
96	}
97	
98	function buildMetricsPayload(
99	  m: SessionMetrics,
100	): StatusLineCommandInput['metrics'] {
101	  const models: StatusLineCommandInput['metrics']['models'] = {};
102	  for (const [id, mm] of Object.entries(m.models)) {
103	    models[id] = {
104	      api: {
105	        total_requests: mm.api.totalRequests,
106	        total_errors: mm.api.totalErrors,
107	        total_latency_ms: mm.api.totalLatencyMs,
108	      },
109	      tokens: {
110	        prompt: mm.tokens.prompt,
111	        completion: mm.tokens.candidates,
112	        total: mm.tokens.total,
113	        cached: mm.tokens.cached,
114	        thoughts: mm.tokens.thoughts,
115	      },
116	    };
117	  }
118	  return {
119	    models,
120	    files: {
121	      total_lines_added: m.files.totalLinesAdded,
122	      total_lines_removed: m.files.totalLinesRemoved,
123	    },
124	  };
125	}
126	
127	/**
128	 * Hook that executes a user-configured shell command and returns its output
129	 * for display in the status line. The command receives structured JSON context
130	 * via stdin.
131	 *
132	 * Updates are debounced (300ms) and triggered by state changes (model switch,
133	 * new messages, vim mode toggle) rather than blind polling.
134	 */
135	export function useStatusLine(): {
136	  text: string | null;
137	} {
138	  const settings = useSettings();
139	  const uiState = useUIState();
140	  const config = useConfig();
141	  const { vimEnabled, vimMode } = useVimMode();
142	
143	  const statusLineConfig = getStatusLineConfig(settings);
144	  const statusLineCommand = statusLineConfig?.command;
145	
146	  const [output, setOutput] = useState<string | null>(null);
147	
148	  // Keep latest values in refs so the stable doUpdate callback can read them
149	  // without being recreated on every render.
150	  const uiStateRef = useRef(uiState);
151	  uiStateRef.current = uiState;
152	  const configRef = useRef(config);
153	  configRef.current = config;
154	  const vimEnabledRef = useRef(vimEnabled);
155	  vimEnabledRef.current = vimEnabled;
156	  const vimModeRef = useRef(vimMode);
157	  vimModeRef.current = vimMode;
158	  const statusLineCommandRef = useRef(statusLineCommand);
159	  statusLineCommandRef.current = statusLineCommand;
160	
161	  const debounceTimerRef = useRef<ReturnType<typeof setTimeout> | undefined>(
162	    undefined,
163	  );
164	
165	  // Track previous trigger values to detect actual changes.
166	  // Initialized with current values so the state-change effect
167	  // does not fire redundantly on mount.
168	  const { lastPromptTokenCount } = uiState.sessionStats;
169	  const { currentModel, branchName } = uiState;
170	  const totalToolCalls = uiState.sessionStats.metrics.tools.totalCalls;
171	  const totalLinesAdded = uiState.sessionStats.metrics.files.totalLinesAdded;
172	  const totalLinesRemoved =
173	    uiState.sessionStats.metrics.files.totalLinesRemoved;
174	  const effectiveVim = vimEnabled ? vimMode : undefined;
175	  const prevStateRef = useRef<{
176	    promptTokenCount: number;
177	    currentModel: string;
178	    effectiveVim: string | undefined;
179	    branchName: string | undefined;
180	    totalToolCalls: number;
181	    totalLinesAdded: number;
182	    totalLinesRemoved: number;
183	  }>({
184	    promptTokenCount: lastPromptTokenCount,
185	    currentModel,
186	    effectiveVim,
187	    branchName,
188	    totalToolCalls,
189	    totalLinesAdded,
190	    totalLinesRemoved,
191	  });
192	
193	  // Guard: when true, the mount effect has already called doUpdate so the
194	  // command-change effect should skip its first run to avoid a double exec.
195	  const hasMountedRef = useRef(false);
196	
197	  // Track the active child process so we can kill it on new updates / unmount.
198	  const activeChildRef = useRef<ChildProcess | undefined>(undefined);
199	  const generationRef = useRef(0);
200	
201	  const doUpdate = useCallback(() => {
202	    const cmd = statusLineCommandRef.current;
203	    if (!cmd) {
204	      setOutput(null);
205	      return;
206	    }
207	
208	    const ui = uiStateRef.current;
209	    const cfg = configRef.current;
210	    const stats = ui.sessionStats;
211	    const m = stats.metrics;
212	
213	    const contextWindowSize =
214	      cfg.getContentGeneratorConfig()?.contextWindowSize || 0;
215	    const usedPercentage =
216	      contextWindowSize > 0
217	        ? Math.min(
218	            100,
219	            Math.max(
220	              0,
221	              Math.round(
222	                (stats.lastPromptTokenCount / contextWindowSize) * 1000,
223	              ) / 10,
224	            ),
225	          )
226	        : 0;
227	
228	    let totalInputTokens = 0;
229	    let totalOutputTokens = 0;
230	    for (const mm of Object.values(m.models)) {
231	      totalInputTokens += mm.tokens.prompt;
232	      totalOutputTokens += mm.tokens.candidates;
233	    }
234	
235	    const input: StatusLineCommandInput = {
236	      session_id: stats.sessionId,
237	      version: cfg.getCliVersion() || 'unknown',
238	      model: {
239	        display_name: ui.currentModel || cfg.getModel() || 'unknown',
240	      },
241	      context_window: {
242	        context_window_size: contextWindowSize,
243	        used_percentage: usedPercentage,
244	        remaining_percentage: Math.round((100 - usedPercentage) * 10) / 10,
245	        current_usage: stats.lastPromptTokenCount,
246	        total_input_tokens: totalInputTokens,
247	        total_output_tokens: totalOutputTokens,
248	      },
249	      workspace: {
250	        current_dir: cfg.getTargetDir(),
251	      },
252	      ...(ui.branchName && {
253	        git: {
254	          branch: ui.branchName,
255	        },
256	      }),
257	      metrics: buildMetricsPayload(m),
258	      ...(vimEnabledRef.current && {
259	        vim: { mode: vimModeRef.current },
260	      }),
261	    };
262	
263	    // Kill the previous child process if still running.
264	    if (activeChildRef.current) {
265	      activeChildRef.current.kill();
266	      activeChildRef.current = undefined;
267	    }
268	
269	    // Bump generation so earlier in-flight callbacks are ignored.
270	    const gen = ++generationRef.current;
271	
272	    const child = exec(
273	      cmd,
274	      { cwd: cfg.getTargetDir(), timeout: 5000, maxBuffer: 1024 * 10 },
275	      (error, stdout) => {
276	        if (gen !== generationRef.current) return; // stale
277	        activeChildRef.current = undefined;
278	        if (!error && stdout) {
279	          // Strip only the trailing newline to preserve intentional whitespace.
280	          const line = stdout.replace(/\r?\n$/, '').split(/\r?\n/, 1)[0];
281	          setOutput(line || null);
282	        } else {
283	          setOutput(null);
284	        }
285	      },
286	    );
287	
288	    activeChildRef.current = child;
289	
290	    // Pass structured JSON context via stdin.
