76	/**
77	 * Strip characters that can break terminal rendering.
78	 *
79	 * Uses Node.js built-in stripVTControlCharacters to handle VT sequences,
80	 * then filters remaining control characters that can disrupt display.
81	 *
82	 * Characters stripped:
83	 * - ANSI escape sequences (via strip-ansi)
84	 * - VT control sequences (via Node.js util.stripVTControlCharacters)
85	 * - C0 control chars (0x00-0x1F) except TAB/CR/LF which are handled elsewhere
86	 * - C1 control chars (0x80-0x9F) that can cause display issues
87	 *
88	 * Characters preserved:
89	 * - All printable Unicode including emojis
90	 * - DEL (0x7F) - handled functionally by applyOperations, not a display issue
91	 * - TAB (0x09) - needed for pasted tab-separated data (e.g. from spreadsheets)
92	 * - CR/LF (0x0D/0x0A) - needed for line breaks
93	 */
94	export function stripUnsafeCharacters(str: string): string {
95	  const strippedAnsi = stripAnsi(str);
96	  const strippedVT = stripVTControlCharacters(strippedAnsi);
97	
98	  return toCodePoints(strippedVT)
99	    .filter((char) => {
100	      const code = char.codePointAt(0);
101	      if (code === undefined) return false;
102	
103	      // Preserve TAB/CR/LF for line handling and pasted tabular data
104	      if (code === 0x09 || code === 0x0a || code === 0x0d) return true;
105	
106	      // Remove C0 control chars (except CR/LF) that can break display
107	      // Examples: BELL(0x07) makes noise, BS(0x08) moves cursor, VT(0x0B), FF(0x0C)
108	      if (code >= 0x00 && code <= 0x1f) return false;
109	
110	      // Remove C1 control chars (0x80-0x9f) - legacy 8-bit control codes
111	      if (code >= 0x80 && code <= 0x9f) return false;
112	
113	      // Preserve DEL (0x7f) - it's handled functionally by applyOperations as backspace
114	      // and doesn't cause rendering issues when displayed
115	
116	      // Preserve all other characters including Unicode/emojis
117	      return true;
118	    })
