154	/* Recursively traverses a JSON-like structure (objects, arrays, primitives)
155	 * and escapes all ANSI control characters found in any string values.
156	 *
157	 * This function is designed to be robust, handling deeply nested objects and
158	 * arrays. It applies a regex-based replacement to all string values to
159	 * safely escape control characters.
160	 *
161	 * To optimize performance, this function uses a "copy-on-write" strategy.
162	 * It avoids allocating new objects or arrays if no nested string values
163	 * required escaping, returning the original object reference in such cases.
164	 *
165	 * @param obj The JSON-like value (object, array, string, etc.) to traverse.
166	 * @returns A new value with all nested string fields escaped, or the
167	 * original `obj` reference if no changes were necessary.
168	 */
169	export function escapeAnsiCtrlCodes<T>(obj: T): T {
170	  if (typeof obj === 'string') {
171	    if (obj.search(regex) === -1) {
172	      return obj; // No changes return original string
173	    }
174	
175	    regex.lastIndex = 0; // needed for global regex
176	    return obj.replace(regex, (match) =>
177	      JSON.stringify(match).slice(1, -1),
178	    ) as T;
179	  }
180	
181	  if (obj === null || typeof obj !== 'object') {
182	    return obj;
183	  }
184	
185	  if (Array.isArray(obj)) {
186	    let newArr: unknown[] | null = null;
187	
188	    for (let i = 0; i < obj.length; i++) {
189	      const value = obj[i];
190	      const escapedValue = escapeAnsiCtrlCodes(value);
191	      if (escapedValue !== value) {
192	        if (newArr === null) {
193	          newArr = [...obj];
194	        }
195	        newArr[i] = escapedValue;
196	      }
197	    }
198	    return (newArr !== null ? newArr : obj) as T;
199	  }
200	
201	  let newObj: T | null = null;
202	  const keys = Object.keys(obj);
203	
204	  for (const key of keys) {
205	    const value = (obj as Record<string, unknown>)[key];
206	    const escapedValue = escapeAnsiCtrlCodes(value);
207	
208	    if (escapedValue !== value) {
209	      if (newObj === null) {
210	        newObj = { ...obj };
211	      }
212	      (newObj as Record<string, unknown>)[key] = escapedValue;
213	    }
214	  }
215	
216	  return newObj !== null ? newObj : obj;
217	}
