    });

    it('returns null when command fails', async () => {
      setStatusLineConfig({ type: 'command', command: 'bad-cmd' });
      const { result } = renderHook(() => useStatusLine());

      await act(async () => {
        execCallback(new Error('command not found'), '', '');
