'use strict';

module.exports = function ansiRegex({ onlyFirst = false } = {}) {
  // Keep this in sync with ansi-regex v6.2.x. It is bundled as CommonJS so both
  // legacy CJS consumers and modern ESM default imports receive a callable export.
  const ST = '(?:\\u0007|\\u001B\\u005C|\\u009C)';
  const osc = `(?:\\u001B\\][\\s\\S]*?${ST})`;
  const csi =
    '[\\u001B\\u009B][[\\]\\()#;?]*(?:\\d{1,4}(?:[;:]\\d{0,4})*)?[\\dA-PR-TZcf-nq-uy=><~]';

  return new RegExp(`${osc}|${csi}`, onlyFirst ? undefined : 'g');
};

