    loader: { '.node': 'file' },
    plugins: [wasmBinaryPlugin, wasmLoader({ mode: 'embedded' })],
    metafile: true,
    write: true,
    keepNames: true,
  })
  .then(({ metafile }) => {
    if (process.env.DEV === 'true') {
